CREATE OR REPLACE FUNCTION menage.check_pivot_tenant_coherence_taches()
RETURNS TRIGGER AS $$
DECLARE
    chambre_hotel   BIGINT;
    personnel_hotel BIGINT;
BEGIN
    SELECT hotel_id INTO chambre_hotel FROM hebergement.chambres
        WHERE chambre_id = NEW.chambre_id;
    IF chambre_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant tache rejected: chambre_id=% not found',
            NEW.chambre_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM chambre_hotel THEN
        RAISE EXCEPTION 'Cross-tenant tache rejected: tache.hotel_id=% chambre.hotel_id=%',
            NEW.hotel_id, chambre_hotel;
    END IF;

    IF NEW.personnel_id IS NOT NULL THEN
        SELECT hotel_id INTO personnel_hotel FROM menage.personnel
            WHERE personnel_id = NEW.personnel_id;
        IF personnel_hotel IS NULL THEN
            RAISE EXCEPTION 'Cross-tenant tache rejected: personnel_id=% not found',
                NEW.personnel_id;
        END IF;
        IF NEW.hotel_id IS DISTINCT FROM personnel_hotel THEN
            RAISE EXCEPTION 'Cross-tenant tache rejected: tache.hotel_id=% personnel.hotel_id=%',
                NEW.hotel_id, personnel_hotel;
        END IF;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION menage.check_pivot_tenant_coherence_planning()
RETURNS TRIGGER AS $$
DECLARE
    personnel_hotel BIGINT;
BEGIN
    SELECT hotel_id INTO personnel_hotel FROM menage.personnel
        WHERE personnel_id = NEW.personnel_id;
    IF personnel_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant planning rejected: personnel_id=% not found',
            NEW.personnel_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM personnel_hotel THEN
        RAISE EXCEPTION 'Cross-tenant planning rejected: planning.hotel_id=% personnel.hotel_id=%',
            NEW.hotel_id, personnel_hotel;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION menage.check_pivot_tenant_coherence_historique()
RETURNS TRIGGER AS $$
DECLARE
    tache_hotel     BIGINT;
    chambre_hotel   BIGINT;
    personnel_hotel BIGINT;
    user_hotel      BIGINT;
BEGIN
    IF NEW.tache_id IS NOT NULL THEN
        SELECT hotel_id INTO tache_hotel FROM menage.taches
            WHERE tache_id = NEW.tache_id;
        IF tache_hotel IS NOT NULL AND NEW.hotel_id IS DISTINCT FROM tache_hotel THEN
            RAISE EXCEPTION 'Cross-tenant historique rejected: historique.hotel_id=% tache.hotel_id=%',
                NEW.hotel_id, tache_hotel;
        END IF;
    END IF;

    SELECT hotel_id INTO chambre_hotel FROM hebergement.chambres
        WHERE chambre_id = NEW.chambre_id;
    IF chambre_hotel IS NULL THEN
        RAISE EXCEPTION 'Cross-tenant historique rejected: chambre_id=% not found',
            NEW.chambre_id;
    END IF;
    IF NEW.hotel_id IS DISTINCT FROM chambre_hotel THEN
        RAISE EXCEPTION 'Cross-tenant historique rejected: historique.hotel_id=% chambre.hotel_id=%',
            NEW.hotel_id, chambre_hotel;
    END IF;

    IF NEW.personnel_id IS NOT NULL THEN
        SELECT hotel_id INTO personnel_hotel FROM menage.personnel
            WHERE personnel_id = NEW.personnel_id;
        IF personnel_hotel IS NOT NULL AND NEW.hotel_id IS DISTINCT FROM personnel_hotel THEN
            RAISE EXCEPTION 'Cross-tenant historique rejected: historique.hotel_id=% personnel.hotel_id=%',
                NEW.hotel_id, personnel_hotel;
        END IF;
    END IF;

    IF NEW.user_id IS NOT NULL THEN
        SELECT hotel_id INTO user_hotel FROM core.dbusers
            WHERE user_id = NEW.user_id;
        IF user_hotel IS NOT NULL AND NEW.hotel_id IS DISTINCT FROM user_hotel THEN
            RAISE EXCEPTION 'Cross-tenant historique rejected: historique.hotel_id=% user.hotel_id=%',
                NEW.hotel_id, user_hotel;
        END IF;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql
